DELIMITER $$
--
-- Procedures
--
CREATE DEFINER=`root`@`localhost` PROCEDURE `finalizar_ticket` (IN `p_ticket_id` INT, IN `p_estado` INT)   BEGIN
    -- Validar existencia
    IF NOT EXISTS (SELECT 1 FROM tickets WHERE id = p_ticket_id) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Error: El Ticket no existe';
    END IF;

    UPDATE tickets
    SET 
        estado = p_estado,
        finalizado_at = CURRENT_TIMESTAMP
    WHERE id = p_ticket_id;
    
    -- actualizar detail:

UPDATE
    ticket_detail
SET
    final_at = NOW()
WHERE
    ticket_id = p_ticket_id
    ORDER BY id DESC 
LIMIT 1;

    -- Retornar resultado
    SELECT id AS ticket_id, numero, estado, finalizado_at
    FROM tickets
    WHERE id = p_ticket_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `generar_numero_ticket` (IN `p_servicio_id` INT, OUT `p_numero` VARCHAR(20))   BEGIN
    DECLARE v_codigo VARCHAR(10);
    DECLARE v_ultimo_numero VARCHAR(20);
    DECLARE v_correlativo INT;

    -- Obtener código del servicio
    SELECT codigo INTO v_codigo
    FROM servicios
    WHERE id = p_servicio_id
    LIMIT 1;

    IF v_codigo IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Error: Servicio no existe';
    END IF;

    -- Obtener último correlativo del día
    -- Optimizamos usando CAST y SUBSTRING de forma segura
    SELECT numero INTO v_ultimo_numero
    FROM tickets
    WHERE servicio_id = p_servicio_id
      AND DATE(created_at) = CURDATE()
    ORDER BY id DESC
    LIMIT 1;

    IF v_ultimo_numero IS NULL THEN
        SET v_correlativo = 1;
    ELSE
        SET v_correlativo = CAST(SUBSTRING_INDEX(v_ultimo_numero, '-', -1) AS UNSIGNED) + 1;
    END IF;

    SET p_numero = CONCAT(v_codigo, '-', LPAD(v_correlativo, 3, '0'));
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `llamar_ticket` (IN `p_ticket_id` INT, IN `p_usuario_id` INT, IN `p_puesto_id` INT, IN `p_servicio_id` INT)   BEGIN
    DECLARE
        v_numero VARCHAR(20) ; DECLARE v_id_persona INT ; DECLARE v_detail_id INT ;
    START TRANSACTION
        ;
        -- Bloqueo de fila para evitar condiciones de carrera (FOR UPDATE)
    SELECT
        numero,
        id_persona
    INTO v_numero, v_id_persona
FROM
    tickets
WHERE
    id = p_ticket_id FOR UPDATE ; IF v_numero IS NULL THEN
ROLLBACK
    ; SIGNAL SQLSTATE '45000'
SET MESSAGE_TEXT
    = 'Error: Ticket no existe' ;
END IF ;
UPDATE
    tickets
SET
    estado = 2,
    -- Estado: Llamado
    puesto_id = p_puesto_id,
    usuario_id = p_usuario_id,
    servicio_id = p_servicio_id
WHERE
    id = p_ticket_id ;
    -- Buscar el ID del último detalle para este ticket
SELECT
    id
INTO v_detail_id
FROM
    ticket_detail
WHERE
    ticket_id = p_ticket_id
ORDER BY
    id
DESC
LIMIT 1 ; IF v_detail_id IS NOT NULL THEN
-- Actualizar último registro
UPDATE
    ticket_detail
SET
    llamado_veces = llamado_veces + 1,
    id_puesto = p_puesto_id,
    id_usuario = p_usuario_id,
    id_servicio = p_servicio_id,
    id_persona = v_id_persona,
    llamado_at = NOW()
WHERE
    id = v_detail_id ; ELSE
    -- Insertar primer registro
INSERT INTO ticket_detail(
    ticket_id,
    id_servicio,
    id_puesto,
    id_usuario,
    id_persona,
    op_comment,
    transferir,
    llamado_veces,
    llamado_at
)
VALUES(
    p_ticket_id,
    p_servicio_id,
    p_puesto_id,
    p_usuario_id,
    v_id_persona,
    '',
    0,
    1,
    NOW()
) ;
END IF ;
COMMIT
    ;
SELECT
    p_ticket_id AS ticket_id,
    v_numero AS numero ;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `transferir` (IN `p_ticket_id` INT, IN `p_usuario_id` INT, IN `p_servicio_nvo` INT, IN `p_comentario` VARCHAR(255))   BEGIN
    DECLARE v_id_persona INT;
    DECLARE v_puesto_id INT;
    DECLARE v_existe INT DEFAULT 0;

    START TRANSACTION;

    -- Validar existencia y bloquear
    SELECT id_persona, puesto_id, 1 
    INTO v_id_persona, v_puesto_id, v_existe
    FROM tickets
    WHERE id = p_ticket_id
    FOR UPDATE;

    IF v_existe = 0 THEN
        ROLLBACK;
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Error: Ticket no existe';
    END IF;
    
-- Actualiza el último detalle abierto de este ticket
UPDATE ticket_detail 
SET final_at = NOW() 
WHERE ticket_id = p_ticket_id 
  AND final_at IS NULL
ORDER BY id DESC 
LIMIT 1;

    -- Insertar historial de transferencia
    INSERT INTO ticket_detail (
        ticket_id, id_servicio, id_puesto, id_usuario, 
        id_persona, op_comment, transferir, llamado_veces 
    )
    VALUES (
        p_ticket_id, p_servicio_nvo, v_puesto_id, 
        p_usuario_id, v_id_persona, p_comentario, 1, 0
    );

    -- Actualizar ticket a estado "En espera" (1) y limpiar puesto/usuario
    UPDATE tickets
    SET 
        servicio_id = p_servicio_nvo,
        usuario_id = NULL,
        puesto_id = NULL,
        estado = 1
    WHERE id = p_ticket_id;

    COMMIT;

    SELECT * FROM tickets WHERE id = p_ticket_id;
END$$

DELIMITER ;

