CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `estadisticas_diarias`  AS SELECT cast(`tickets`.`created_at` as date) AS `fecha`, count(0) AS `total_tickets`, sum(case when `tickets`.`estado` = 'atendido' then 1 else 0 end) AS `atendidos`, sum(case when `tickets`.`estado` = 'no_presentado' then 1 else 0 end) AS `no_presentados`, sum(case when `tickets`.`estado` = 'espera' then 1 else 0 end) AS `en_espera`, avg(timestampdiff(MINUTE,`tickets`.`created_at`,coalesce(`tickets`.`finalizado_at`,current_timestamp()))) AS `tiempo_promedio` FROM `tickets` GROUP BY cast(`tickets`.`created_at` as date) ;

